#!/usr/bin/env node

/**
 * Build Slides Skill - Evaluation Pipeline
 *
 * Complete workflow:
 * 1. Accept path to HTML file generated by /build-slides skill
 * 2. Automatically evaluate against the rubric
 * 3. Append results to master EVALUATIONS.md report
 *
 * Usage:
 *   npm run eval:auto -- --html-path results/my-slides.html --prompt-name "my-slides" --prompt-text "Your prompt here"
 *   npm run eval:auto -- --html-path results/my-slides.html  (derives name from filename)
 */

const fs = require('fs');
const path = require('path');
const { autoEvaluate } = require('./lib/auto-evaluator');
const { initializeReport, addEvaluation, getNextEvaluationNumber, generateSummary } = require(
  './lib/consolidated-reporter'
);
const { getProvider, getModel } = require('./lib/config-loader');

const RESULTS_DIR = path.join(__dirname, 'results');
const EVALUATIONS_REPORT = path.join(RESULTS_DIR, 'EVALUATIONS.md');

// Helper functions
const log = {
  info: (msg) => console.log(`ℹ️  ${msg}`),
  success: (msg) => console.log(`✓ ${msg}`),
  error: (msg) => console.error(`✗ ${msg}`),
  header: (msg) => console.log(`\n${'='.repeat(70)}\n${msg}\n${'='.repeat(70)}\n`),
};

// Parse command line arguments
function parseArgs() {
  const args = process.argv.slice(2);
  const result = { htmlPath: null, promptName: null, promptText: null };

  for (let i = 0; i < args.length; i++) {
    if (args[i] === '--html-path' && i + 1 < args.length) {
      result.htmlPath = args[i + 1];
      i++;
    } else if (args[i] === '--prompt-name' && i + 1 < args.length) {
      result.promptName = args[i + 1];
      i++;
    } else if (args[i] === '--prompt-text' && i + 1 < args.length) {
      result.promptText = args[i + 1];
      i++;
    }
  }

  return result;
}

// Derive prompt name from HTML file path
function derivePromptName(htmlPath) {
  const filename = path.basename(htmlPath, '.html');
  return filename;
}

// Main function
async function main() {
  const args = parseArgs();

  log.header('Build Slides Skill - Automated Evaluation Pipeline');

  try {
    // Show configuration
    const provider = getProvider();
    const model = getModel();
    log.info(`Using ${provider} • Model: ${model}\n`);

    // Validate input
    if (!args.htmlPath) {
      log.error('Usage:');
      log.info('  npm run eval:auto -- --html-path results/my-slides.html');
      log.info('  npm run eval:auto -- --html-path results/my-slides.html --prompt-name "my-slides" --prompt-text "Your prompt"');
      log.info('\nFirst time? Run: npm run eval:setup');
      process.exit(1);
    }

    // Validate HTML file exists
    const htmlFilePath = path.resolve(args.htmlPath);
    if (!fs.existsSync(htmlFilePath)) {
      throw new Error(`HTML file not found: ${htmlFilePath}`);
    }

    // Derive prompt name from filename if not provided
    let promptName = args.promptName || derivePromptName(htmlFilePath);
    let promptText = args.promptText || '';

    log.info(`Evaluating: ${promptName}`);
    if (promptText) {
      log.info(`Prompt: "${promptText.substring(0, 60)}${promptText.length > 60 ? '...' : ''}"`);
    }

    // Ensure results directory exists
    if (!fs.existsSync(RESULTS_DIR)) {
      fs.mkdirSync(RESULTS_DIR, { recursive: true });
    }

    // Initialize consolidated report
    initializeReport(RESULTS_DIR);

    // Step 1: Evaluate slides
    log.info(`\n🔍 Step 1: Evaluate Slides`);
    const scores = await autoEvaluate(htmlFilePath, promptText, promptName);

    // Step 2: Add to consolidated report
    log.info(`\n📊 Step 2: Update Consolidated Report`);
    const evalNumber = getNextEvaluationNumber(EVALUATIONS_REPORT);
    const relativeHtmlPath = `./${path.basename(htmlFilePath)}`;

    addEvaluation(EVALUATIONS_REPORT, {
      number: evalNumber,
      promptName,
      promptText,
      htmlFile: relativeHtmlPath,
      readability: scores.readability,
      composition: scores.composition,
      consistency: scores.consistency,
      functionality: scores.functionality,
      timestamp: new Date().toISOString(),
      notes: scores.notes,
    });

    log.success(`Added to consolidated report as evaluation #${evalNumber}`);

    // Summary
    const summary = generateSummary(EVALUATIONS_REPORT);

    log.header('✅ EVALUATION COMPLETE');

    log.info(`Evaluation #: ${evalNumber}`);
    log.info(`Prompt: ${promptName}`);
    log.info(`\nScores:`);
    log.info(`  Readability: ${scores.readability}/5`);
    log.info(`  Composition: ${scores.composition}/5`);
    log.info(`  Consistency: ${scores.consistency}/5`);
    log.info(`  Functionality: ${scores.functionality}`);
    log.info(`  Visual Quality Avg: ${(
      (scores.readability + scores.composition + scores.consistency) /
      3
    ).toFixed(1)}/5`);

    if (scores.notes) {
      log.info(`\nNotes: ${scores.notes}`);
    }

    log.info(`\n📂 Files:`);
    log.info(`  HTML Slides: ${htmlFilePath}`);
    log.info(`  Report: EVALUATIONS.md`);

    if (summary) {
      log.info(`\n📈 Consolidated Report Summary:`);
      log.info(`  Total Evaluations: ${summary.totalEvaluations}`);
      log.info(`  Avg Visual Quality: ${summary.averageVisualQuality}/5.0`);
      log.info(`  Avg Readability: ${summary.averageReadability}/5.0`);
      log.info(`  Avg Composition: ${summary.averageComposition}/5.0`);
      log.info(`  Avg Consistency: ${summary.averageConsistency}/5.0`);
      log.info(`  Functionality Pass Rate: ${summary.functionalityPassRate}%`);
    }

    log.info(`\n🔗 View Results:`);
    log.info(`  Open in browser: ${htmlFilePath}`);
    log.info(`  Check report: ${EVALUATIONS_REPORT}`);
  } catch (error) {
    log.error(error.message);
    process.exit(1);
  }
}

main();
